/*
 * Rebound, tool demo overrides.
 * Loaded after the generated demos to replace any that read poorly. The physics
 * card demos (spring / recoil / bounce) are generated by SAMPLING the real
 * easing engine, so the looping showcase plays the exact motion the tool
 * produces, not a hand-tuned approximation. Smooth morphs a jagged polyline into
 * a flowing one (same point count, so the path never snaps).
 */
;(function (R) {
  'use strict';
  if (!R.registerToolDemo) return;

  function r(v) { return Math.round(v * 100) / 100; }

  // Build a looping SMIL value/keyTime pair by sampling fn(t) for t in [0,1]
  // over the play portion, holding at the settled value, then resetting. `map`
  // turns a sampled value into the attribute string; `resetVal` is the start.
  function sampleSMIL(fn, n, playEnd, map, resetVal) {
    var values = [];
    var keyTimes = [];
    for (var i = 0; i <= n; i++) {
      var t = i / n;
      values.push(map(fn(t)));
      keyTimes.push(r(t * playEnd));
    }
    values.push(map(fn(1)));
    keyTimes.push(0.9);
    values.push(resetVal);
    keyTimes.push(1);
    return { values: values.join(';'), keyTimes: keyTimes.join(';') };
  }

  var sampler = R.easing && R.easing.sampler;

  // ---- Spring / Recoil / Bounce: exact engine motion ----------------------
  if (sampler) {
    // Spring: a square pops in with the engine's real overshoot (scale).
    var springFn = sampler.toFunction({ type: 'spring', response: 0.5, bounce: 0.35 });
    var sp = sampleSMIL(springFn, 32, 0.6, function (v) { return r(v); }, '0');
    R.registerToolDemo('spring',
      '<strong>Spring.</strong> The engine’s real physical overshoot, settling onto the target.',
      '<svg viewBox="0 0 120 72" preserveAspectRatio="xMidYMid meet"><g transform="translate(60,38)">' +
        '<rect x="-17" y="-13" width="34" height="26" rx="5" style="fill:var(--rb-accent)">' +
        '<animateTransform attributeName="transform" type="scale" values="' + sp.values + '" ' +
        'keyTimes="' + sp.keyTimes + '" dur="3s" calcMode="linear" repeatCount="indefinite"/>' +
        '</rect></g></svg>');

    // Recoil: a box flies to its mark and overshoots past it, then settles
    // (the same damped oscillation, mapped to horizontal travel).
    var recoilFn = sampler.toFunction({ type: 'spring', response: 0.42, bounce: 0.42 });
    var rc = sampleSMIL(recoilFn, 32, 0.6, function (v) { return r((v - 1) * 62) + ',0'; }, '-62,0');
    R.registerToolDemo('recoil',
      '<strong>Recoil.</strong> Velocity-driven overshoot past the mark, then a quick settle.',
      '<svg viewBox="0 0 120 72" preserveAspectRatio="xMidYMid meet">' +
        '<line x1="60" y1="16" x2="60" y2="56" stroke="currentColor" stroke-width="1" stroke-dasharray="2 3" opacity="0.3"/>' +
        '<rect x="45" y="24" width="30" height="24" rx="4" style="fill:var(--rb-accent)">' +
        '<animateTransform attributeName="transform" type="translate" values="' + rc.values + '" ' +
        'keyTimes="' + rc.keyTimes + '" dur="3.2s" calcMode="linear" repeatCount="indefinite"/>' +
        '</rect></svg>');

    // Bounce: a ball falls to the floor and rebounds, each bounce smaller. Uses
    // the SAME parametric bounce the Bounce tool's preview plays.
    var bounceFn = makeBounce(0.7, 4);
    var bc = sampleSMIL(bounceFn, 40, 0.64, function (v) { return r(14 + 36 * v); }, '14');
    R.registerToolDemo('bounce',
      '<strong>Bounce.</strong> A gravitational rebound off the target, each bounce smaller.',
      '<svg viewBox="0 0 120 72" preserveAspectRatio="xMidYMid meet">' +
        '<line x1="18" y1="58" x2="102" y2="58" stroke="currentColor" stroke-width="1.5" opacity="0.3"/>' +
        '<circle cx="60" r="8" style="fill:var(--rb-accent)">' +
        '<animate attributeName="cy" values="' + bc.values + '" keyTimes="' + bc.keyTimes + '" ' +
        'dur="2.8s" calcMode="linear" repeatCount="indefinite"/>' +
        '</circle></svg>');
  }

  // The exact bounce model from features/bounce.js, so the card matches the tool.
  function makeBounce(elas, bounces) {
    var e = Math.max(0.15, Math.min(0.85, elas));
    var n = Math.max(1, Math.min(5, Math.round(bounces)));
    var widths = [1.0];
    var drops = [];
    var base = 0.2 + 0.12 * e;
    for (var k = 1; k <= n; k++) { var d = base * Math.pow(e, k - 1); drops.push(d); widths.push(2.4 * Math.sqrt(d)); }
    var total = 0, i;
    for (i = 0; i < widths.length; i++) total += widths[i];
    var nw = widths.map(function (x) { return x / total; });
    var starts = [0];
    for (i = 1; i < nw.length; i++) starts.push(starts[i - 1] + nw[i - 1]);
    return function (t) {
      if (t <= 0) return 0;
      if (t >= 1) return 1;
      if (t < starts[1]) { var u = t / nw[0]; return u * u * (3 - 2 * u); }
      for (var s = 1; s <= n; s++) {
        var s0 = starts[s];
        var s1 = (s < n) ? starts[s + 1] : 1;
        if (t < s1 || s === n) {
          var u2 = (t - s0) / (s1 - s0);
          return 1 - drops[s - 1] * 4 * u2 * (1 - u2);
        }
      }
      return 1;
    };
  }

  // ---- Smooth: jagged polyline relaxes into a flowing one ------------------
  // Both paths sample the SAME x positions, so only the y values morph and the
  // line never snaps. Jagged y is piecewise-linear (sharp corners); smooth y is
  // a Catmull-Rom curve (flowing). 6 shared keyframe x positions.
  var KX = [14, 32, 52, 71, 90, 106];
  var JY = [50, 18, 54, 20, 48, 28];
  var SY = [41, 34, 38, 33, 36, 36];

  function catmull(Y, seg, t) {
    var p0 = Y[Math.max(0, seg - 1)];
    var p1 = Y[seg];
    var p2 = Y[seg + 1];
    var p3 = Y[Math.min(Y.length - 1, seg + 2)];
    var t2 = t * t;
    var t3 = t2 * t;
    return 0.5 * ((2 * p1) + (-p0 + p2) * t + (2 * p0 - 5 * p1 + 4 * p2 - p3) * t2 + (-p0 + 3 * p1 - 3 * p2 + p3) * t3);
  }

  (function () {
    var N = 30;
    var segs = KX.length - 1;
    var jd = '';
    var sd = '';
    for (var i = 0; i <= N; i++) {
      var u = (i / N) * segs;
      var seg = Math.min(segs - 1, Math.floor(u));
      var t = u - seg;
      var x = KX[seg] + (KX[seg + 1] - KX[seg]) * t;
      var jy = JY[seg] + (JY[seg + 1] - JY[seg]) * t; // linear: angular
      var sy = catmull(SY, seg, t);                   // curved: flowing
      jd += (i ? 'L' : 'M') + r(x) + ' ' + r(jy) + ' ';
      sd += (i ? 'L' : 'M') + r(x) + ' ' + r(sy) + ' ';
    }
    jd = jd.replace(/\s+$/, '');
    sd = sd.replace(/\s+$/, '');

    var dots = '';
    for (var k = 0; k < KX.length; k++) {
      dots += '<circle cx="' + KX[k] + '" cy="' + JY[k] + '" r="2.7">' +
        '<animate attributeName="cy" values="' + JY[k] + ';' + SY[k] + ';' + SY[k] + ';' + JY[k] + '" ' +
        'keyTimes="0;0.42;0.8;1" dur="4s" calcMode="spline" ' +
        'keySplines="0.34 1.45 0.5 1;0 0 1 1;0.5 0 0.6 1" repeatCount="indefinite"/></circle>';
    }

    R.registerToolDemo('smooth',
      '<strong>Smooth keyframes.</strong> A jagged, angular path relaxes into a flowing curve, then repeats.',
      '<svg viewBox="0 0 120 72" preserveAspectRatio="xMidYMid meet">' +
        '<path fill="none" style="stroke:var(--rb-accent)" stroke-width="2" stroke-linejoin="round" stroke-linecap="round" d="' + jd + '">' +
        '<animate attributeName="d" values="' + jd + ';' + sd + ';' + sd + ';' + jd + '" ' +
        'keyTimes="0;0.42;0.8;1" dur="4s" calcMode="spline" ' +
        'keySplines="0.4 0 0.2 1;0 0 1 1;0.5 0 0.6 1" repeatCount="indefinite"/></path>' +
        '<g style="fill:var(--rb-accent)">' + dots + '</g>' +
        '</svg>');
  })();
})(window.Rebound = window.Rebound || {});
